import React, { useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import "./forgotpassword.css"; // Import CSS for styling

const ForgotPasswordPage = () => {
  const [userEmail, setUserEmail] = useState("");
  const [otpMessage, setOtpMessage] = useState("");
  const [otpError, setOtpError] = useState("");
  const navigate = useNavigate();

  const handlePasswordResetRequest = async (e) => {
    e.preventDefault();
    setOtpMessage("");
    setOtpError("");

    try {
      const response = await axios.post("http://localhost:5000/api/auth/forgot-password", { email: userEmail });

      if (response.data.exists) {
        setOtpMessage(response.data.message);
        setTimeout(() => navigate("/verify-otp"), 2000); // Redirect to OTP verification
      } else {
        setOtpError(response.data.message);
      }
    } catch (err) {
      setOtpError("Error sending OTP. Try again.");
      console.error("Forgot Password Error:", err);
    }
  };

  return (
    <div className="forgot-password-wrapper">
      <h2>Forgot Password</h2>
      <p>Enter your registered email to receive an OTP</p>
      <form onSubmit={handlePasswordResetRequest}>
        <input
          type="email"
          placeholder="Enter your email"
          value={userEmail}
          onChange={(e) => setUserEmail(e.target.value)}
          required
        />
        <button type="submit">Send OTP</button>
      </form>
      {otpMessage && <p className="success-message">{otpMessage}</p>}
      {otpError && <p className="error-message">{otpError}</p>}
    </div>
  );
};

export default ForgotPasswordPage;
